def get_stats(numbers):
    if len(numbers) == 0:
        return None
    total = 0
    for n in numbers:
        total = total + n
    mean = total / len(numbers)
    sorted_nums = []
    for n in numbers:
        inserted = False
        for i in range(len(sorted_nums)):
            if n < sorted_nums[i]:
                sorted_nums.insert(i, n)
                inserted = True
                break
        if not inserted:
            sorted_nums.append(n)
    if len(sorted_nums) % 2 == 0:
        median = (sorted_nums[len(sorted_nums)//2 - 1] + sorted_nums[len(sorted_nums)//2]) / 2
    else:
        median = sorted_nums[len(sorted_nums)//2]
    return {'mean': mean, 'median': median, 'min': sorted_nums[0], 'max': sorted_nums[-1]}
